 50	static void goep_rfcomm_connected(struct bt_rfcomm_dlc *dlc)
 51	{
 52		struct bt_goep *goep = CONTAINER_OF(dlc, struct bt_goep, _transport.dlc);
 53		int err;
 54	
 55		LOG_DBG("RFCOMM %p connected", dlc);
 56	
 57		if (dlc->mtu < GOEP_MIN_MTU) {
 58			LOG_WRN("Invalid MTU %d", dlc->mtu);
 59			bt_rfcomm_dlc_disconnect(dlc);
 60			return;
 61		}
 62		goep->obex.rx.mtu = dlc->mtu;
 63		goep->obex.tx.mtu = dlc->mtu;
 64	
 65		atomic_set(&goep->_state, BT_GOEP_TRANSPORT_CONNECTED);
 66	
 67		err = bt_obex_transport_connected(&goep->obex);
 68		if (err) {
 69			LOG_WRN("Notify OBEX (err %d). Disconnecting transport...", err);
 70			bt_rfcomm_dlc_disconnect(dlc);
 71			return;
 72		}
 73	
 74		if (goep->transport_ops->connected) {
 75			goep->transport_ops->connected(goep->_acl, goep);
 76		}
 77	}
