104	static int goep_rfcomm_send(struct bt_obex *obex, struct net_buf *buf)
105	{
106		struct bt_goep *goep = CONTAINER_OF(obex, struct bt_goep, obex);
107		int err;
108	
109		if (goep->_goep_v2) {
110			LOG_WRN("Invalid transport");
111			return -EINVAL;
112		}
113	
114		if (buf->len > obex->tx.mtu) {
115			LOG_WRN("Packet size exceeds MTU");
116			return -EMSGSIZE;
117		}
118	
119		if (net_buf_tailroom(buf) < BT_RFCOMM_FCS_SIZE) {
120			LOG_WRN("No tailroom for RFCOMM FCS field");
121			return -EMSGSIZE;
122		}
123	
124		err = bt_rfcomm_dlc_send(&goep->_transport.dlc, buf);
125		if (err < 0) {
126			return err;
127		}
128	
129		return 0;
130	}
