 33	static struct net_buf *obex_alloc_buf(struct bt_obex *obex)
 34	{
 35		struct net_buf *buf;
 36	
 37		if (obex == NULL || obex->_transport_ops == NULL ||
 38		    obex->_transport_ops->alloc_buf == NULL) {
 39			LOG_WRN("Buffer allocation is unsupported");
 40			return NULL;
 41		}
 42	
 43		buf = obex->_transport_ops->alloc_buf(obex, NULL);
 44		if (!buf) {
 45			LOG_WRN("Fail to alloc buffer");
 46		}
 47		return buf;
 48	}
 49	
 50	static int obex_send(struct bt_obex *obex, uint16_t mopl, struct net_buf *buf)
 51	{
 52		if (obex == NULL || obex->_transport_ops == NULL || obex->_transport_ops->send == NULL) {
 53			LOG_WRN("OBEX sending is unsupported");
 54			return -EIO;
 55		}
 56	
 57		if (buf->len > mopl) {
 58			LOG_WRN("Data length too long (%d > %d)", buf->len, mopl);
 59			return -EMSGSIZE;
 60		}
 61	
 62		return obex->_transport_ops->send(obex, buf);
 63	}
