 65	static int obex_transport_disconn(struct bt_obex *obex)
 66	{
 67		int err;
 68	
 69		if (obex == NULL || obex->_transport_ops == NULL ||
 70		    obex->_transport_ops->disconnect == NULL) {
 71			LOG_WRN("OBEX transport disconn is unsupported");
 72			return -EIO;
 73		}
 74	
 75		err = obex->_transport_ops->disconnect(obex);
 76		if (err) {
 77			LOG_ERR("Fail to disconnect transport (err %d)", err);
 78		}
 79		return err;
 80	}
