 82	struct bt_obex_has_header {
 83		uint8_t id;
 84		bool found;
 85	};
 86	
 87	static bool bt_obex_has_header_cb(struct bt_obex_hdr *hdr, void *user_data)
 88	{
 89		struct bt_obex_has_header *data;
 90	
 91		data = user_data;
 92	
 93		if (hdr->id == data->id) {
 94			data->found = true;
 95			return false;
 96		}
 97		return true;
 98	}
 99	
100	bool bt_obex_has_header(struct net_buf *buf, uint8_t id)
101	{
102		struct bt_obex_has_header data;
103		int err;
104	
105		if (buf == NULL) {
106			LOG_WRN("Invalid parameter");
107			return false;
108		}
109	
110		data.id = id;
111		data.found = false;
112	
113		err = bt_obex_header_parse(buf, bt_obex_has_header_cb, &data);
114		if (err != 0) {
115			return false;
116		}
117	
118		return data.found;
119	}
