121	int bt_obex_make_uuid(union bt_obex_uuid *uuid, const uint8_t *data, uint16_t len)
122	{
123		switch (len) {
124		case BT_UUID_SIZE_16:
125			uuid->uuid.type = BT_UUID_TYPE_16;
126			uuid->u16.val = sys_get_be16(data);
127			break;
128		case BT_UUID_SIZE_32:
129			uuid->uuid.type = BT_UUID_TYPE_32;
130			uuid->u32.val = sys_get_be32(data);
131			break;
132		case BT_UUID_SIZE_128:
133			uuid->uuid.type = BT_UUID_TYPE_128;
134			sys_memcpy_swap(uuid->u128.val, data, len);
135			break;
136		default:
137			LOG_WRN("Unsupported UUID len %u", len);
138			return -EINVAL;
139		}
140	
141		return 0;
142	}
