150	static int obex_server_connect(struct bt_obex_server *server, uint16_t len, struct net_buf *buf)
151	{
152		struct bt_obex_conn_req_hdr *hdr;
153		struct bt_obex_conn_rsp_hdr *rsp_conn_hdr;
154		struct bt_obex_rsp_hdr *rsp_hdr;
155		uint8_t version;
156		__maybe_unused uint8_t flags;
157		uint16_t mopl;
158		uint8_t rsp_code;
159		int err;
160		uint16_t target_len;
161		const uint8_t *target_data;
162	
163		LOG_DBG("");
164	
165		if ((len != buf->len) || (buf->len < sizeof(*hdr))) {
166			LOG_WRN("Invalid packet size");
167			rsp_code = BT_OBEX_RSP_CODE_PRECON_FAIL;
168			goto failed;
169		}
170	
171		if (atomic_get(&server->_state) != BT_OBEX_DISCONNECTED) {
172			LOG_WRN("Invalid state, connect refused");
173			rsp_code = BT_OBEX_RSP_CODE_FORBIDDEN;
174			goto failed;
175		}
176	
177		if (server->ops->connect == NULL) {
178			LOG_WRN("Conn req handling not implemented");
179			rsp_code = BT_OBEX_RSP_CODE_NOT_IMPL;
180			goto failed;
181		}
182	
183		if (!atomic_cas(&server->_opcode, 0, BT_OBEX_OPCODE_CONNECT)) {
184			LOG_WRN("Unexpected conn request");
185			rsp_code = BT_OBEX_RSP_CODE_FORBIDDEN;
186			goto failed;
187		}
188	
189		version = net_buf_pull_u8(buf);
190		flags = net_buf_pull_u8(buf);
191		mopl = net_buf_pull_be16(buf);
192	
193		atomic_set_bit_to(&server->_flags, BT_OBEX_HAS_TARGET,
194				  bt_obex_has_header(buf, BT_OBEX_HEADER_ID_TARGET));
195	
196		err = bt_obex_get_header_target(buf, &target_len, &target_data);
197		if (err != 0 && atomic_test_bit(&server->_flags, BT_OBEX_HAS_TARGET)) {
198			LOG_WRN("Invalid target header");
199			rsp_code = BT_OBEX_RSP_CODE_PRECON_FAIL;
200			goto failed;
